package main

import (
	"bytes"
	"html/template"
	"strings"
	"time"
)

func RenderPreviewHTML(approvalID string, items []ScheduleItem, activeRevision int, newRevision int) (string, error) {
	data := struct {
		ApprovalID     string
		GeneratedAt    string
		ActiveRevision int
		NewRevision    int
		Items          []ScheduleItem
	}{approvalID, time.Now().Format("2006-01-02 15:04:05"), activeRevision, newRevision, items}
	tpl := template.Must(template.New("preview").Funcs(template.FuncMap{
		"clock": formatClock,
	}).Parse(previewTemplate))
	var buf bytes.Buffer
	if err := tpl.Execute(&buf, data); err != nil {
		return "", err
	}
	return buf.String(), nil
}

func renderPage(wr *bytes.Buffer, name string, data PageData) error {
	tpl := template.Must(template.New("base").Funcs(template.FuncMap{
		"clock": func(s string) string {
			if t, err := time.Parse(time.RFC3339, s); err == nil {
				return t.Format("15:04")
			}
			return s
		},
		"dateOnly": func(s string) string {
			if t, err := time.Parse(time.RFC3339, s); err == nil {
				return t.Format("2006-01-02")
			}
			return s
		},
		"monthPad": func(m int) string { return time.Month(m).String() },
		"joinDates": func(days []CalendarDay) string {
			var out []string
			for _, d := range days {
				if d.IsSelected {
					out = append(out, d.Date)
				}
			}
			return strings.Join(out, ",")
		},
	}).Parse(baseTemplate + dashboardTemplate + usersTemplate + shiftsTemplate + scheduleTemplate + approvalsTemplate + historyTemplate))
	return tpl.ExecuteTemplate(wr, name, data)
}

