const scheduleTemplate = `{{define "schedule"}}{{template "layout_start" .}}<div class="card"><div class="calendar-head"><a class="btn secondary" href="/schedule?year={{.CalendarPrevYear}}&month={{.CalendarPrevMonth}}&date={{.SelectedDate}}">上月</a><div><h2>{{.CalendarYear}} 年 {{.CalendarMonth}} 月排班设置</h2><div class="hint">点击一个或多个日期，再点击“设置所选日期排班”。提交后需 Telegram 审批通过才生效。</div></div><a class="btn secondary" href="/schedule?year={{.CalendarNextYear}}&month={{.CalendarNextMonth}}&date={{.SelectedDate}}">下月</a></div><div class="calendar selectable" id="scheduleCalendar"><div class="weekday">周一</div><div class="weekday">周二</div><div class="weekday">周三</div><div class="weekday">周四</div><div class="weekday">周五</div><div class="weekday">周六</div><div class="weekday">周日</div>{{range .CalendarDays}}<button type="button" class="day {{if not .IsCurrentMonth}}dim{{end}} {{if .IsToday}}today{{end}}" data-date="{{.Date}}" {{if not .IsCurrentMonth}}disabled{{end}}><div class="daynum">{{.Day}}</div><div class="items">{{range .Items}}<span class="chip">{{.StaffName}} {{.ShiftShortName}}</span>{{end}}</div></button>{{end}}</div><div class="row" style="margin-top:14px"><button type="button" onclick="openScheduleModal()">设置所选日期排班</button><button type="button" class="btn secondary" onclick="clearSelectedDates()">清空选择</button><span class="hint" id="selectedHint">尚未选择日期</span></div></div><div class="card"><h2>{{.SelectedDate}} 当前排班</h2><table><thead><tr><th>用户名</th><th>班次</th><th>时间</th><th>是否通知</th><th>是否已读</th></tr></thead><tbody>{{range .SelectedDayItems}}<tr><td>{{.StaffName}}</td><td><span class="badge">{{.ShiftName}}</span></td><td>{{clock .StartTime}} - {{clock .EndTime}}</td><td><span class="pill {{.NotifyStatus}}">{{.NotifyStatusLabel}}</span></td><td><span class="pill {{.ReadStatus}}">{{.ReadStatusLabel}}</span></td></tr>{{else}}<tr><td colspan="5">当天没有排班</td></tr>{{end}}</tbody></table></div><div class="modal-backdrop" id="scheduleModal"><div class="modal"><h2>设置所选日期排班</h2><p class="muted">已选日期：<span id="modalDates">-</span></p><form method="post" action="/schedule/submit"><input type="hidden" name="year" value="{{.CalendarYear}}"><input type="hidden" name="month" value="{{.CalendarMonth}}"><input type="hidden" name="selected_dates" id="selectedDatesInput"><div class="grid"><div><h3>班次</h3><select name="shift_code" required>{{range .Shifts}}{{if .Enabled}}<option value="{{.Code}}">{{.Name}} {{.Start}}-{{.End}}</option>{{end}}{{end}}</select></div><div><h3>提交人</h3><input name="created_by" value="admin"></div></div><h3>选择用户</h3><div class="checkbox-grid">{{range .Users}}{{if .Enabled}}<label class="checkbox-card"><input type="checkbox" name="staff_ids" value="{{.ID}}">{{.Name}}</label>{{end}}{{end}}</div><div class="row" style="margin-top:18px"><button type="submit">提交 Telegram 审批</button><button type="button" class="btn secondary" onclick="closeScheduleModal()">取消</button></div></form></div></div><script>
const selectedDates = new Set();
function updateSelectedUI(){const arr=[...selectedDates].sort();document.querySelectorAll('#scheduleCalendar .day').forEach(el=>{el.classList.toggle('selected', selectedDates.has(el.dataset.date));});document.getElementById('selectedHint').textContent=arr.length?('已选择 '+arr.length+' 天：'+arr.join(', ')):'尚未选择日期';document.getElementById('selectedDatesInput').value=arr.join(',');document.getElementById('modalDates').textContent=arr.length?arr.join(', '):'-';}
document.querySelectorAll('#scheduleCalendar .day').forEach(el=>{el.addEventListener('click',()=>{const d=el.dataset.date;if(!d)return;if(selectedDates.has(d)){selectedDates.delete(d)}else{selectedDates.add(d)}updateSelectedUI();});});
function clearSelectedDates(){selectedDates.clear();updateSelectedUI();}
function openScheduleModal(){if(selectedDates.size===0){alert('请先在日历中选择日期');return;}updateSelectedUI();document.getElementById('scheduleModal').classList.add('show');}
function closeScheduleModal(){document.getElementById('scheduleModal').classList.remove('show');}
updateSelectedUI();
</script>{{template "layout_end" .}}{{end}}`

